import pytest

class Database:
    def connect(self): return True
    def close(self): pass

@pytest.fixture
def db_connection():
    db = Database()
    db.connect() # Setup
    yield db     # Provide the fixture to the test
    db.close()   # Teardown (runs after test)

def test_database_is_connected(db_connection):
    assert db_connection.connect() is True

import requests
from unittest.mock import patch

def fetch_user_name(user_id):
    response = requests.get(f'https://api.example.com/users/{user_id}')
    return response.json().get('name')

@patch('requests.get')
def test_fetch_user_name(mock_get):
    # Configure the mock to return a specific JSON response
    mock_get.return_value.json.return_value = {'name': 'Alice'}

    result = fetch_user_name(1)

    assert result == 'Alice'
    mock_get.assert_called_once_with('https://api.example.com/users/1')

import pytest

def divide(a, b):
    if b == 0:
        raise ValueError('Cannot divide by zero')
    return a / b

def test_divide_by_zero_raises_error():
    with pytest.raises(ValueError) as exc_info:
        divide(10, 0)

    assert str(exc_info.value) == 'Cannot divide by zero'

