import pytest
def get_discount(price, pct):
    if not 0 <= pct <= 100: raise ValueError()
    return price * (1 - pct/100)

def test_normal(): assert get_discount(100, 20) == 80
def test_zero_pct(): assert get_discount(100, 0) == 100
def test_full_pct(): assert get_discount(100, 100) == 0
def test_invalid():
    with pytest.raises(ValueError):
        get_discount(100, 110)
